solutionCode:
function summarizeSlot(slot, txCount, seconds, finalized) {
  const tps = txCount / seconds;
  return {
    slot,
    tps,
    healthy: finalized && tps >= 1000,
  };
}

testCode:
const r1 = summarizeSlot(101, 20000, 10, true);
assert(r1.slot === 101, 'slot mismatch');
assert(r1.tps === 2000, 'tps mismatch');
assert(r1.healthy === true, 'healthy should be true');

const r2 = summarizeSlot(102, 3000, 5, false);
assert(r2.healthy === false, 'healthy should be false when not finalized');
